    '11111111-1111-1111-1111-111111111132',  -- baseline-bidder-23
    '11111111-1111-1111-1111-111111111133',  -- baseline-bidder-24
    '11111111-1111-1111-1111-111111111134',  -- baseline-bidder-25
    '11111111-1111-1111-1111-111111111135',  -- baseline-bidder-26
    '11111111-1111-1111-1111-111111111136',  -- baseline-bidder-27
